func dispatchWpp_(slot uint32, recv unsafe.Pointer, w0 unsafe.Pointer, w1 unsafe.Pointer) {
	var pw [2]unsafe.Pointer
	var sw [0]uint64
	var fw [0]float64
	pw[0] = w0
	pw[1] = w1
	var rpw [0]unsafe.Pointer
	var rsw [0]uint64
	var rfw [0]float64
	if core := slotPoolWpp_[slot]; core != nil {
		core(recv, pw[:], sw[:], fw[:], rpw[:], rsw[:], rfw[:])
	}
}

func init() {
	registerWordPool("pp_", &wordPool{
		next:  &nextSlotWpp_,
		cap:   poolSizeWpp_,
		stubs: stubsWpp_[:],
		slots: slotPoolWpp_[:],
		name:  "Wpp_",
	})
}
